+    // Find best scoring agent
+    let bestAgent = '';
+    let bestScore = 0;
+    let bestMatched: string[] = [];
+
+    for (const [agent, data] of Object.entries(scores)) {
+      if (data.score > bestScore) {
+        bestScore = data.score;
+        bestAgent = agent;
+        bestMatched = data.matched;
+      }
+    }
